    38→
    39→function formatDuration(startedAt?: string, completedAt?: string): string {
    40→  if (!startedAt) return "--";
    41→  const start = new Date(startedAt).getTime();
    42→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    43→  const secs = Math.round((end - start) / 1000);
    44→  if (secs < 60) return `${secs}s`;
    45→  const mins = Math.floor(secs / 60);
    46→  const rem = secs % 60;
    47→  return `${mins}m ${rem}s`;
    48→}
    49→
    50→function truncate(str: string, max: number): string {
    51→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    52→}
