            <DialogTitle>Add Source</DialogTitle>
          </DialogHeader>
          <SourceForm
            title="Add Source"
            projectId={project.id}
            onSubmit={async (input) => {
              const res = await sourcesApi.create(project.id, input);
              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
