   289→function ProjectCompactRow({ project }: { project: Project }) {
   290→  const router = useRouter();
   291→  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
   292→    releasesApi.listByProject(project.id, 1, 5)
   293→  );
   294→  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
   295→    sourcesApi.listByProject(project.id)
   296→  );
   297→  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
   298→    srApi.list(project.id, 1, 3)
   299→  );
   300→
   301→  const releases = relData?.data ?? [];
   302→  const sources = srcData?.data ?? [];
   303→  const srItems = srData?.data ?? [];
   304→  const latest = releases[0];
   305→  const latestSr = srItems[0];
   306→
   307→  const sourceMap = new Map<string, Source>();
   308→  for (const s of sources) sourceMap.set(s.id, s);
   309→
   310→  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
   311→  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
   312→
   313→  const urgencyStyle = latestSr?.report?.urgency
   314→    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
   315→    : undefined;
   316→
   317→  return (
   318→    <div
   319→      onClick={() => router.push(`/projects/${project.id}`)}
   320→      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-[#f9f9f7] cursor-pointer"
   321→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   322→    >
   323→      {/* Project name */}
   324→      <span
   325→        className="flex items-center gap-2 text-[14px] font-bold shrink-0"
   326→        style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a", minWidth: "160px" }}
   327→      >
   328→        <ProjectLogo name={project.name} sources={sources} size={24} />
   329→        {project.name}
   330→      </span>
   331→
   332→      {/* Latest release */}
   333→      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
   334→        {latest ? (
   335→          <>
   336→            <Link
   337→              href={`/releases/${latest.id}`}
   338→              onClick={(e) => e.stopPropagation()}
   339→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
   340→              style={{
   341→                backgroundColor: "#f3f3f1",
   342→                fontFamily: "'JetBrains Mono', monospace",
   343→                color: "#374151",
   344→              }}
   345→            >
   346→              {latest.version}
   347→            </Link>
   348→            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
   349→          </>
   350→        ) : (
   351→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   352→            No releases
   353→          </span>
   354→        )}
   355→      </span>
   356→
   357→      {/* Latest semantic release */}
   358→      <span className="flex items-center gap-1.5 flex-1 min-w-0">
   359→        {latestSr ? (
   360→          <>
   361→            <Link
   362→              href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
   363→              onClick={(e) => e.stopPropagation()}
   364→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0 hover:ring-1 hover:ring-blue-300 transition-shadow"
   365→              style={{
   366→                backgroundColor: "#eff6ff",
   367→                fontFamily: "'JetBrains Mono', monospace",
   368→                color: "#1d4ed8",
   369→              }}
   370→            >
   371→              {latestSr.version}
   372→            </Link>
   373→            {urgencyStyle && (
   374→              <span
   375→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
   376→                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   377→              >
   378→                {latestSr.report?.urgency}
   379→              </span>
   380→            )}
   381→            {latestSr.report?.summary && (
   382→              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   383→                {latestSr.report.summary.length > 60
   384→                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
   385→                  : latestSr.report.summary}
   386→              </span>
   387→            )}
   388→          </>
   389→        ) : (
   390→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   391→            No analysis
   392→          </span>
   393→        )}
   394→      </span>
   395→
   396→      {/* Arrow */}
   397→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
   398→    </div>
   399→  );
