   447→              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
   448→              placeholder="Search projects..."
   449→              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
   450→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
