   463→              <LayoutGrid className="h-4 w-4" />
   464→            </button>
   465→            <button
   466→              onClick={() => setViewMode("compact")}
   467→              className="p-1.5 rounded-r-md transition-colors"
   468→              style={{
   469→                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
   470→                color: viewMode === "compact" ? "#111113" : "#9ca3af",
   471→              }}
   472→              title="Compact view"
   473→            >
   474→              <List className="h-4 w-4" />
   475→            </button>
   476→          </div>
   477→          <button
   478→            onClick={() => setCreateOpen(true)}
   479→            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   480→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   481→          >
   482→            <Plus className="h-3.5 w-3.5" />
