   110→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   111→      </div>
   112→      <div className="space-y-2">
   113→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   114→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
