   122→          rows={4}
   123→          className="font-mono text-sm"
   124→          placeholder="{}"
   125→        />
   126→      </div>
   127→      <div className="space-y-2">
   128→        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   129→        <Input
   130→          id="version_filter_include"
