   136→        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   137→      </div>
   138→      <div className="space-y-2">
   139→        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   140→        <Input
