   308→  const latestSr = srItems[0];
   309→
   310→  const sourceMap = useMemo(() => {
   311→    const m = new Map<string, Source>();
   312→    for (const s of sources) m.set(s.id, s);
   313→    return m;
   314→  }, [sources]);
   315→
   316→  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
   317→  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
   318→
   319→  const urgencyStyle = latestSr?.report?.urgency
   320→    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
   321→    : undefined;
   322→
   323→  return (
   324→    <div
   325→      onClick={() => router.push(`/projects/${project.id}`)}
   326→      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-[#f9f9f7] cursor-pointer"
   327→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   328→    >
   329→      {/* Project name */}
   330→      <span
   331→        className="flex items-center gap-2 text-[14px] font-bold shrink-0"
   332→        style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a", minWidth: "160px" }}
   333→      >
   334→        <ProjectLogo name={project.name} sources={sources} size={24} />
   335→        {project.name}
   336→      </span>
   337→
   338→      {/* Latest release */}
   339→      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
   340→        {latest ? (
   341→          <>
   342→            <Link
   343→              href={`/releases/${latest.id}`}
   344→              onClick={(e) => e.stopPropagation()}
   345→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
   346→              style={{
   347→                backgroundColor: "#f3f3f1",
   348→                fontFamily: "'JetBrains Mono', monospace",
   349→                color: "#374151",
   350→              }}
   351→            >
   352→              {latest.version}
   353→            </Link>
   354→            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
   355→          </>
   356→        ) : (
   357→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   358→            No releases
   359→          </span>
   360→        )}
   361→      </span>
   362→
   363→      {/* Latest semantic release */}
   364→      <span className="flex items-center gap-1.5 flex-1 min-w-0">
   365→        {latestSr ? (
   366→          <>
   367→            <Link
   368→              href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
   369→              onClick={(e) => e.stopPropagation()}
   370→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0 hover:ring-1 hover:ring-blue-300 transition-shadow"
   371→              style={{
   372→                backgroundColor: "#eff6ff",
   373→                fontFamily: "'JetBrains Mono', monospace",
   374→                color: "#1d4ed8",
   375→              }}
   376→            >
   377→              {latestSr.version}
   378→            </Link>
   379→            {urgencyStyle && (
   380→              <span
   381→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
   382→                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   383→              >
   384→                {latestSr.report?.urgency}
   385→              </span>
   386→            )}
   387→            {latestSr.report?.summary && (
   388→              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   389→                {latestSr.report.summary.length > 60
   390→                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
   391→                  : latestSr.report.summary}
   392→              </span>
   393→            )}
   394→          </>
   395→        ) : (
   396→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   397→            No analysis
   398→          </span>
   399→        )}
   400→      </span>
   401→
   402→      {/* Arrow */}
   403→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
   404→    </div>
   405→  );
   406→}
   407→
   408→/* ---------- Page ---------- */
   409→
   410→export default function ProjectsPage() {
   411→  const [createOpen, setCreateOpen] = useState(false);
   412→  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
   413→  const [search, setSearch] = useState("");
   414→  const [page, setPage] = useState(1);
   415→  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
   416→  const items = data?.data ?? [];
   417→
   418→  const PAGE_SIZE = 12;
   419→  const filtered = search
   420→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
   421→    : items;
   422→  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
   423→  const currentPage = Math.min(page, totalPages);
   424→  const paged = filtered.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
   425→
   426→  return (
   427→    <div className="flex flex-col gap-4 fade-in">
   428→      <div className="flex items-center justify-between">
   429→        <div>
   430→          <h1
   431→            style={{
   432→              fontFamily: "var(--font-fraunces)",
