   450→            <input
   451→              type="text"
   452→              value={search}
   453→              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
   454→              placeholder="Search projects..."
   455→              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
   456→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   457→            />
   458→          </div>
