   472→              onClick={() => setViewMode("compact")}
   473→              className="p-1.5 rounded-r-md transition-colors"
   474→              style={{
   475→                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
   476→                color: viewMode === "compact" ? "#111113" : "#9ca3af",
   477→              }}
   478→              title="Compact view"
   479→            >
   480→              <List className="h-4 w-4" />
   481→            </button>
   482→          </div>
   483→          <button
