   485→            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   486→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   487→          >
   488→            <Plus className="h-3.5 w-3.5" />
   489→            New Project
   490→          </button>
   491→        </div>
   492→      </div>
   493→
   494→      {isLoading ? (
   495→        <p
   496→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   497→          style={{ fontFamily: "var(--font-fraunces)" }}
   498→        >
   499→          Loading...
   500→        </p>
   501→      ) : items.length === 0 ? (
   502→        <div
   503→          className="flex flex-col items-center justify-center rounded-md border py-12"
   504→          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   505→        >
   506→          <p
   507→            className="text-[14px] italic text-[#9ca3af]"
   508→            style={{ fontFamily: "var(--font-fraunces)" }}
   509→          >
   510→            No projects yet — create one to start tracking releases
   511→          </p>
   512→          <button
   513→            onClick={() => setCreateOpen(true)}
   514→            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   515→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   516→          >
   517→            <Plus className="h-3.5 w-3.5" />
   518→            New Project
   519→          </button>
   520→        </div>
   521→      ) : filtered.length === 0 ? (
   522→        <p
   523→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   524→          style={{ fontFamily: "var(--font-fraunces)" }}
   525→        >
   526→          No projects matching &ldquo;{search}&rdquo;
   527→        </p>
   528→      ) : (
   529→        <>
   530→          <div className={viewMode === "cards" ? "space-y-5" : "space-y-1.5"}>
   531→            {paged.map((project) =>
   532→              viewMode === "cards" ? (
   533→                <ProjectFlowCard key={project.id} project={project} />
   534→              ) : (
   535→                <ProjectCompactRow key={project.id} project={project} />
   536→              )
   537→            )}
   538→          </div>
   539→          {totalPages > 1 && (
