/* ---------- Project Card Logo ---------- */

function ProjectCardLogo({ projectId, name }: { projectId: string; name: string }) {
  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
    sourcesApi.listByProject(projectId)
  );
  return <ProjectLogo name={name} sources={data?.data} size={40} />;
}

/* ---------- Overflow Flow ---------- */

const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
const MAX_LINES = 2;

function FlowSection({
  label,
  labelColor,
  moreHref,
  children,
}: {
  label: string;
  labelColor?: string;
  moreHref: string;
  children: React.ReactNode;
}) {
  const innerRef = useRef<HTMLDivElement>(null);
  const [overflows, setOverflows] = useState(false);

  const check = useCallback(() => {
    const el = innerRef.current;
    if (!el) return;
    setOverflows(el.scrollHeight > LINE_HEIGHT * MAX_LINES + 4);
  }, []);

  useEffect(() => {
    check();
    const obs = new ResizeObserver(check);
    if (innerRef.current) obs.observe(innerRef.current);
    return () => obs.disconnect();
  }, [check, children]);

  return (
    <div className="text-[13px] leading-7">
      <div
        ref={innerRef}
        style={{ maxHeight: LINE_HEIGHT * MAX_LINES, overflow: "hidden" }}
      >
        <span
          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
          style={{ color: labelColor ?? "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
        >
          {label}:
        </span>
        {children}
      </div>
      {overflows && (
        <Link
          href={moreHref}
          className="text-[12px] font-medium hover:underline"
          style={{ color: "#e8601a" }}
        >
          more…
        </Link>
      )}
    </div>
  );
}

