/* ---------- Overflow Flow ---------- */

const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
const MAX_LINES = 2;

function FlowSection({
  label,
  moreHref,
  children,
}: {
  label: string;
  moreHref: string;
  children: React.ReactNode;
}) {
  const innerRef = useRef<HTMLDivElement>(null);
  const [overflows, setOverflows] = useState(false);

  const check = useCallback(() => {
    const el = innerRef.current;
    if (!el) return;
    setOverflows(el.scrollHeight > LINE_HEIGHT * MAX_LINES + 4);
  }, []);

  useEffect(() => {
    check();
    const obs = new ResizeObserver(check);
    if (innerRef.current) obs.observe(innerRef.current);
    return () => obs.disconnect();
  }, [check, children]);

  return (
    <div className="relative text-[13px] leading-7">
      <div
        ref={innerRef}
        style={{ maxHeight: LINE_HEIGHT * MAX_LINES, overflow: "hidden" }}
      >
        <span
          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
        >
          {label}:
        </span>
        {children}
      </div>
      {overflows && (
        <Link
          href={moreHref}
          className="absolute right-0 text-[12px] font-medium hover:underline pl-6"
          style={{
            color: "#e8601a",
            bottom: 0,
            background: "linear-gradient(to right, transparent, white 40%)",
          }}
        >
          more…
        </Link>
      )}
    </div>
  );
}

