/* ---------- Overflow Flow ---------- */

const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
const MAX_LINES = 2;

function FlowSection({
  label,
  moreHref,
  children,
}: {
  label: string;
  moreHref: string;
  children: React.ReactNode;
}) {
  const outerRef = useRef<HTMLDivElement>(null);
  const innerRef = useRef<HTMLDivElement>(null);
  const [overflows, setOverflows] = useState(false);

  const check = useCallback(() => {
    const el = innerRef.current;
    if (!el) return;
    setOverflows(el.scrollHeight > LINE_HEIGHT * MAX_LINES + 4);
  }, []);

  useEffect(() => {
    check();
    const obs = new ResizeObserver(check);
    if (innerRef.current) obs.observe(innerRef.current);
    return () => obs.disconnect();
  }, [check, children]);

  return (
    <div ref={outerRef} className="text-[13px] leading-7" style={{ maxHeight: LINE_HEIGHT * MAX_LINES, overflow: "hidden" }}>
      <div ref={innerRef}>
        <span
          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
        >
          {label}:
        </span>
        {children}
        {overflows && (
          <Link
            href={moreHref}
            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
            style={{ color: "#e8601a" }}
          >
            more…
          </Link>
        )}
      </div>
    </div>
  );
}

/* ---------- Flow Card ---------- */

