        </div>
      </div>

      {/* Sources chips */}
      <div className="flex flex-wrap items-center gap-1.5 mb-3">
        <span
          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5"
          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
        >
