const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
const MAX_LINES = 2;
const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
const MORE_WIDTH = 48; // approximate width of "more…" link in px

function FlowSection({
  label,
  moreHref,
  children,
}: {
  label: string;
  moreHref: string;
  children: React.ReactNode;
}) {
  const measureRef = useRef<HTMLDivElement>(null);
  const [visibleCount, setVisibleCount] = useState<number | null>(null);

  const items = React.Children.toArray(children);

  const measure = useCallback(() => {
    const el = measureRef.current;
    if (!el) return;
    const nodes = el.children;
    // Check if everything fits without overflow
    if (el.scrollHeight <= MAX_HEIGHT + 4) {
      setVisibleCount(items.length);
      return;
    }
    // Find how many items fit in 2 lines, reserving space for "more…"
    const containerWidth = el.offsetWidth;
    let count = 0;
    for (let i = 1; i < nodes.length; i++) { // skip index 0 (label span)
      const node = nodes[i] as HTMLElement;
      const nodeBottom = node.offsetTop + node.offsetHeight;
      const nodeRight = node.offsetLeft + node.offsetWidth;
      // If this item's bottom exceeds 2 lines, stop before it
      if (nodeBottom > MAX_HEIGHT) break;
      // If this item is on the last visible line, check if "more…" still fits
      if (nodeBottom > LINE_HEIGHT && nodeRight + MORE_WIDTH > containerWidth) break;
      count = i;
    }
    setVisibleCount(Math.max(1, count));
  }, [items.length]);

  useEffect(() => {
    measure();
    const obs = new ResizeObserver(measure);
    if (measureRef.current) obs.observe(measureRef.current);
    return () => obs.disconnect();
  }, [measure, items.length]);

  const hasOverflow = visibleCount !== null && visibleCount < items.length;
  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;

  return (
    <div className="relative">
