    37→
    38→/* ---------- Overflow Flow ---------- */
    39→
    40→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    41→const MAX_LINES = 2;
    42→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    43→const MORE_WIDTH = 48; // approximate width of "more…" link in px
    44→
    45→function FlowSection({
    46→  label,
    47→  moreHref,
    48→  children,
    49→}: {
    50→  label: string;
    51→  moreHref: string;
    52→  children: React.ReactNode;
    53→}) {
    54→  const measureRef = useRef<HTMLDivElement>(null);
    55→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    56→
    57→  const items = React.Children.toArray(children);
    58→
    59→  const measure = useCallback(() => {
    60→    const el = measureRef.current;
    61→    if (!el) return;
    62→    const nodes = el.children;
    63→    // Check if everything fits without overflow
    64→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    65→      setVisibleCount(items.length);
    66→      return;
    67→    }
    68→    // Find how many items fit in 2 lines, reserving space for "more…"
    69→    const containerWidth = el.offsetWidth;
    70→    let count = 0;
    71→    for (let i = 1; i < nodes.length; i++) { // skip index 0 (label span)
    72→      const node = nodes[i] as HTMLElement;
    73→      const nodeBottom = node.offsetTop + node.offsetHeight;
    74→      const nodeRight = node.offsetLeft + node.offsetWidth;
    75→      // If this item's bottom exceeds 2 lines, stop before it
    76→      if (nodeBottom > MAX_HEIGHT) break;
    77→      // If this item is on the last visible line, check if "more…" still fits
    78→      if (nodeBottom > LINE_HEIGHT && nodeRight + MORE_WIDTH > containerWidth) break;
    79→      count = i;
    80→    }
    81→    setVisibleCount(Math.max(1, count));
    82→  }, [items.length]);
    83→
    84→  useEffect(() => {
    85→    measure();
    86→    const obs = new ResizeObserver(measure);
    87→    if (measureRef.current) obs.observe(measureRef.current);
    88→    return () => obs.disconnect();
    89→  }, [measure, items.length]);
    90→
    91→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
    92→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
    93→
    94→  return (
    95→    <div className="relative">
    96→      {/* Hidden measurer — renders all items to find cutoff */}
    97→      <div
    98→        ref={measureRef}
    99→        className="text-[13px] leading-7"
   100→        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   101→        aria-hidden="true"
   102→      >
   103→        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   104→          {label}:
   105→        </span>
   106→        {items}
   107→      </div>
   108→      {/* Visible section */}
   109→      <div className="text-[13px] leading-7">
   110→        <span
   111→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   112→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   113→        >
   114→          {label}:
   115→        </span>
   116→        {displayed}
   117→        {hasOverflow && (
   118→          <Link
   119→            href={moreHref}
   120→            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   121→            style={{ color: "#e8601a" }}
   122→          >
   123→            more…
   124→          </Link>
   125→        )}
   126→      </div>
   127→    </div>
   128→  );
   129→}
