const measure = useCallback(() => {
  const el = measureRef.current;
  if (!el) return;
  const nodes = el.children;
  // Check if everything fits without overflow (exclude the hidden "more…" span at the end)
  if (el.scrollHeight <= MAX_HEIGHT + 4) {
    setVisibleCount(items.length);
    return;
  }
  // Measure actual "more…" link width
  const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 4 : 52;
  const containerWidth = el.offsetWidth;
  // First pass: find all items that fit within 2 lines (ignoring "more…" space)
  let lastFitting = 0;
  for (let i = 1; i < nodes.length - 1; i++) { // skip label (0) and hidden more span (last)
